mapper.select:
SELECT u.id, u.phone, u.real_name, u.gender, u.user_type, u.status, u.last_login_time, u.create_time, r.role_code FROM `user` u LEFT JOIN user_role ur ON u.id = ur.user_id LEFT JOIN role r ON ur.role_id = r.id AND r.status = 1 WHERE u.deleted = 0
AND u.phone LIKE CONCAT('%', #{phone}, '%')
AND u.user_type = #{userType}
AND u.status = #{status}
ORDER BY u.create_time DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(DISTINCT u.id) FROM `user` u LEFT JOIN user_role ur ON u.id = ur.user_id LEFT JOIN role r ON ur.role_id = r.id AND r.status = 1 WHERE u.deleted = 0
AND u.phone LIKE CONCAT('%', #{phone}, '%')
AND u.user_type = #{userType}
AND u.status = #{status}
